function seller(o){const sid=val(o,['SO_SalespersonID','SalespersonID','PS','PS Code']), sn=val(o,['Salesperson_Name','Salesperson Name','SalesName','PSName']); const tid=val(o,['TelesaleId','TelesalesID','TeleSaleID']), tn=val(o,['TelesaleName','TelesalesName','TeleSaleName']); return [sid,sn].filter(Boolean).join(' ')||[tid,tn].filter(Boolean).join(' ')||'ไม่ระบุ PS'}
