function readSheets(wb){for(const name of wb.SheetNames){const ws=wb.Sheets[name], aoa=XLSX.utils.sheet_to_json(ws,{header:1,defval:'',raw:false}); for(let i=0;i<Math.min(100,aoa.length);i++){const h=(aoa[i]||[]).map(T); const score=h.filter(x=>/sku|qty|pcs|ship|customer|sales|tele|invc|invoice|brand|สินค้า|ร้าน/i.test(x)).length; if(score>=3){const rows=aoa.slice(i+1).map(r=>Object.fromEntries(h.map((k,j)=>[k||('c'+j),r[j]]))).map(rowFrom).filter(r=>r.qty||r.amt||r.code); if(rows.length)return rows;}}} return []}
async function readPivot(buf){if(!window.JSZip)return[]; const zip=await JSZip.loadAsync(buf); const defs=Object.keys(zip.files).filter(k=>/^xl\/pivotCache\/pivotCacheDefinition\d+\.xml$/.test(k)).sort(), recs=Object.keys(zip.files).filter(k=>/^xl\/pivotCache\/pivotCacheRecords\d+\.xml$/.test(k)).sort(); for(let z=0;z<Math.min(defs.length,recs.length);z++){const df=zip.file(defs[z]), rf=zip.file(recs[z]); if(!df||!rf)continue; const doc=new DOMParser().parseFromString(await df.async('string'),'text/xml'); const fields=[...doc.getElementsByTagName('cacheField')].map(cf=>{let shared=[]; const si=[...cf.childNodes].find(n=>n.nodeType===1&&n.localName==='sharedItems'); if(si)[...si.childNodes].forEach(ch=>{if(ch.nodeType!==1)return; let v=ch.getAttribute('v')??''; if(ch.localName==='n')v=N(v); if(ch.localName==='d')v=T(v).slice(0,10); if(ch.localName==='m')v=''; shared.push(v)}); return {name:cf.getAttribute('name')||'',shared};}); const wanted=['InvcDate','OrdDate','ShipDateAct','SO_Date','SOTypeID','SO_SalespersonID','SalespersonID','Salesperson_Name','TelesaleId','TelesaleName','ShipName','CustomerName','Customer Name','c_Name','InvcNbr','Invoice_No','InvoiceNo','SKU_Code','SKU_Desc','TAS_THName','ShipQtyPCS','ShipQtyPC','QtyShip','SO_UnitPrice','LineAmtBeforeDisc','TAS_Brand','Brand','GroupBrand','TAS_SizeGroup','SKU_Size']; const sel={}; fields.forEach((f,i)=>{if(wanted.includes(f.name))sel[i]=f.name}); const rtx=await rf.async('string'), out=[]; let rr=/<r>([\s\S]*?)<\/r>/g, er=/<(x|n|s|d|b|m)(?:\s+[^>]*?v="([^"]*)")?[^>]*\/>/g, m, rec=0; const cv=(i,tag,v)=>tag==='x'?(fields[i]?.shared[N(v)]??''):tag==='n'?N(v):tag==='d'?T(v).slice(0,10):tag==='s'?T(v):tag==='b'?v==='1':''; while((m=rr.exec(rtx))){let body=m[1], em, i=0, o={}; er.lastIndex=0; while((em=er.exec(body))){if(sel[i])o[sel[i]]=cv(i,em[1],em[2]); i++} const r=rowFrom(o,rec++); if(r.qty||r.amt||r.code)out.push(r)} if(out.length)return out;} return []}
function dates(){return U(R.map(r=>r.date)).sort()}
function applyFilters(){let q=filters.q.toLowerCase(); return R.filter(r=>(!filters.start||r.date>=filters.start)&&(!filters.end||r.date<=filters.end)&&(!filters.ps||r.ps===filters.ps)&&(!filters.store||r.store===filters.store)&&(!filters.brand||r.brand===filters.brand)&&(!filters.type||r.type===filters.type)&&(!q||[r.date,r.inv,r.code,r.sku,r.store,r.ps,r.brand,r.size,r.type].join(' ').toLowerCase().includes(q)))}
function groupPick(rows){let m=new Map(); rows.forEach(r=>{const k=[r.brand,r.size,r.code||r.sku,r.sku,r.type].join('|'); let x=m.get(k); if(!x){x={k,brand:r.brand,size:r.size,code:r.code,sku:r.sku,type:r.type,qty:0,amt:0,stores:new Map(),bills:new Set(),ps:new Set()};m.set(k,x)} x.qty+=N(r.qty); x.amt+=N(r.amt); x.stores.set(r.store,(x.stores.get(r.store)||0)+N(r.qty)); x.bills.add(r.inv); x.ps.add(r.ps);}); return [...m.values()].sort((a,b)=>a.brand.localeCompare(b.brand,'th')||a.size.localeCompare(b.size,'th')||a.sku.localeCompare(b.sku,'th'))}
function groupDist(rows){let m=new Map(); rows.forEach(r=>{const k=[r.brand,r.size,r.code||r.sku,r.sku,r.type,r.store].join('|'); let x=m.get(k); if(!x){x={k,brand:r.brand,size:r.size,code:r.code,sku:r.sku,type:r.type,store:r.store,qty:0,amt:0,bills:new Set(),ps:new Set()};m.set(k,x)} x.qty+=N(r.qty); x.amt+=N(r.amt); x.bills.add(r.inv); x.ps.add(r.ps);}); return [...m.values()].sort((a,b)=>a.sku.localeCompare(b.sku,'th')||a.store.localeCompare(b.store,'th'))}
