function fillFilters(){const rows=R.filter(r=>(!filters.start||r.date>=filters.start)&&(!filters.end||r.date<=filters.end)); const opt=(id,vals,val)=>{const el=$('#'+id); if(!el)return; el.innerHTML='<option value="">ทั้งหมด</option>'+vals.map(x=>`<option value="${E(x)}">${E(x)}</option>`).join(''); el.value=val||''}; opt('psSelect',U(rows.map(r=>r.ps)).sort((a,b)=>a.localeCompare(b,'th')),filters.ps); opt('storeSelect',U(rows.filter(r=>!filters.ps||r.ps===filters.ps).map(r=>r.store)).sort((a,b)=>a.localeCompare(b,'th')),filters.store); opt('brandSelect',U(rows.map(r=>r.brand)).sort((a,b)=>a.localeCompare(b,'th')),filters.brand); opt('typeSelect',U(rows.map(r=>r.type)).sort(),filters.type); $('#startDate').value=filters.start; $('#endDate').value=filters.end; $('#q').value=filters.q; $('#datePreview').textContent=filters.start||filters.end?`${dlabel(filters.start)} - ${dlabel(filters.end)}`:'ทุกวัน'}
function setTabs(){['modePick','distTab','doneTab','rawTab','shipTab'].forEach(id=>$('#'+id)?.classList.remove('on')); ($('#'+(view==='dist'?'distTab':view==='done'?'doneTab':view==='raw'?'rawTab':view==='ship'?'shipTab':'modePick'))||$('#modePick'))?.classList.add('on')}
function pager(total){const pages=Math.max(1,Math.ceil(total/pageSize)); if(page>pages)page=pages; let h=''; for(let i=1;i<=Math.min(5,pages);i++)h+=`<button class="page ${i===page?'on':''}" data-p="${i}">${i}</button>`; if(pages>5)h+=`<span>...</span><button class="page" data-p="${pages}">${pages}</button>`; h+=`<button class="page" data-n="1">›</button>`; $('#pager').innerHTML=h; $$('[data-p]').forEach(b=>b.onclick=()=>{page=N(b.dataset.p)||1;render()}); $('[data-n]')?.addEventListener('click',()=>{if(page<pages){page++;render()}})}
