function pickTable(groups,onlyDone=false){if(onlyDone)groups=groups.filter(g=>N(done[dkey(g)])>0); const shown=groups.slice((page-1)*pageSize,page*pageSize); let h='<thead><tr><th>#</th><th>แบรนด์/ไซซ์</th><th>SKU</th><th>สินค้า</th><th>ร้านที่คีย์</th><th>บิล</th><th>จำนวนรวม</th><th>จัดแล้ว</th><th>คงเหลือ</th><th>ยอด</th></tr></thead><tbody>'; shown.forEach((g,i)=>{const d=N(done[dkey(g)]), rem=g.qty-d; h+=`<tr><td>${(page-1)*pageSize+i+1}</td><td>${E(g.brand)}<br><small>${E(g.size)} · ${E(g.type)}</small></td><td>${E(g.code||'-')}</td><td class="p"><b>${E(g.sku)}</b><small>${F(g.qty)} ชิ้น · ${F(g.stores.size)} ร้านที่คีย์</small></td><td><button class="mini" data-detail="${E(g.k)}">${F(g.stores.size)} ร้าน</button></td><td>${F(g.bills.size)}</td><td>${F(g.qty)}</td><td><input class="pick" data-k="${E(dkey(g))}" value="${d||''}" inputmode="numeric" type="number"></td><td class="${rem<0?'bad':'good'}">${F(rem)}</td><td>${B(g.amt)}</td></tr>`}); if(!shown.length)h+='<tr><td colspan="10" class="empty">ไม่พบรายการถอดของ</td></tr>'; return {html:h+'</tbody>',total:groups.length,label:'ถอดของ '+F(groups.length)+' รายการ'}}
