function rawTable(rows){const shown=rows.slice((page-1)*pageSize,page*pageSize); let h='<thead><tr><th>#</th><th>วันที่</th><th>บิล</th><th>SKU</th><th>สินค้า</th><th>ร้านที่คีย์</th><th>PS</th><th>จำนวน</th><th>ยอด</th><th>ประเภท</th></tr></thead><tbody>'; shown.forEach((r,i)=>h+=`<tr><td>${(page-1)*pageSize+i+1}</td><td>${E(dlabel(r.date))}</td><td>${E(r.inv)}</td><td>${E(r.code||'-')}</td><td class="p"><b>${E(r.sku)}</b><small>${E(r.brand)} · ${E(r.size)}</small></td><td>${E(r.store)}</td><td>${E(r.ps)}</td><td>${F(r.qty)}</td><td>${B(r.amt)}</td><td>${E(r.type)}</td></tr>`); if(!shown.length)h+='<tr><td colspan="10" class="empty">ไม่พบรายการดิบ</td></tr>'; return {html:h+'</tbody>',total:rows.length,label:'รายการดิบ '+F(rows.length)+' แถว'}}
function shipTable(rows){const to=shipTo||'ยังไม่ได้ระบุร้านรับจริง'; const gs=groupPick(rows), shown=gs.slice((page-1)*pageSize,page*pageSize); let h='<thead><tr><th>#</th><th>ร้านรับจริง</th><th>SKU</th><th>สินค้า</th><th>จำนวนส่งจริง</th><th>ร้านที่คีย์เป็นหลักฐาน</th><th>บิล</th><th>ยอด</th><th>หมายเหตุ</th></tr></thead><tbody>'; shown.forEach((g,i)=>h+=`<tr><td>${(page-1)*pageSize+i+1}</td><td>${E(to)}</td><td>${E(g.code||'-')}</td><td class="p"><b>${E(g.sku)}</b><small>${E(g.brand)} · ${E(g.size)} · ${E(g.type)}</small></td><td>${F(g.qty)}</td><td>${E([...g.stores.entries()].map(([s,q])=>s+' '+F(q)).join(' / '))}</td><td>${F(g.bills.size)}</td><td>${B(g.amt)}</td><td>แยกร้านรับจริงออกจากร้านที่คีย์</td></tr>`); if(!shown.length)h+='<tr><td colspan="9" class="empty">ไม่พบข้อมูลใบส่งร้านจริง</td></tr>'; return {html:h+'</tbody>',total:gs.length,label:'ใบส่งร้านจริง '+F(gs.length)+' รายการ'}}
function bindRowButtons(){$$('.pick').forEach(inp=>inp.onchange=e=>{undo.push(JSON.stringify(done)); redo=[]; done[e.target.dataset.k]=N(e.target.value); render()}); $$('[data-detail]').forEach(btn=>btn.onclick=()=>{const g=groupPick(applyFilters()).find(x=>x.k===btn.dataset.detail); if(!g)return; alert([...g.stores.entries()].map(([s,q])=>`${s}: ${F(q)} ชิ้น`).join('\n'))})}
